def recommend_route(grid, source, target, contingency_scenarios, policy):
    candidates = get_candidate_paths(grid, source, target, k=3)
    resilient_candidates = [
        c for c in candidates
        if all(survives_contingency(grid, c, scenario) for scenario in contingency_scenarios)
    ]
    if not resilient_candidates:
        return {"recommendation": None, "reason": "no candidate survives all specified contingencies"}

    chosen = choose_route(current_state, resilient_candidates, policy)
    return {
        "recommendation": chosen,
        "loss_percent": compute_route_loss(grid, chosen),
        "survives_contingencies": contingency_scenarios,
    }
